1	// trust-origin 신뢰 원점 부트스트랩 선언 CLI.
2	// declare: 선행 10조건 검사 후 trust-origin record를 생성한다. WORKSTATE·applier-log는 수정하지 않는다.
3	// --self-test: $TEMP 사본에서 5개 case를 in-process로 검증한다.
4	using System.Diagnostics;
5	using System.Security.Cryptography;
6	using System.Text;
7	using System.Text.Encodings.Web;
8	using System.Text.Json;
9	using System.Text.Json.Nodes;
10	
11	internal static class TrustOriginCli
12	{
13	    // record 고정 경로 — 이 밖 경로에는 절대 쓰지 않는다.
14	    private const string RecordRelPath = "docs/handoff/trust-origin/TO-2026-001.json";
15	
16	    private static readonly JsonSerializerOptions WriteOptions = new()
17	    {
18	        WriteIndented = true,
19	        Encoder = JavaScriptEncoder.UnsafeRelaxedJsonEscaping,
20	    };
21	
22	    // knownException 항목 데이터 레코드.
23	    private record KnownException(string Code, string Subject, string What, string Why, string WhyNotReplayed);
24	
25	    // 자기 시험 전용 precondition 주입 레코드 — CLI·환경변수로 켤 수 없음.
26	    internal record PreconOverride(
27	        bool BuildVerified, bool FilesTracked, bool NoDirectMod,
28	        string CommitHash, bool AutoLauncherOff, bool HighRiskClosed);
29	
30	    // 자기 시험 seam — in-process 훅만. production 진입점에서 설정 불가.
31	    internal static bool NonInteractiveOverride;
32	    internal static PreconOverride? TestPrecon;
33	
34	    // trust-origin 진입점.
35	    internal static int Run(string[] args)
36	    {
37	        var sub = args.Length > 1 ? args[1] : "";
38	        if (string.Equals(sub, "declare", StringComparison.OrdinalIgnoreCase))
39	            return RunDeclare(args);
40	        if (string.Equals(sub, "--self-test", StringComparison.OrdinalIgnoreCase))
41	            return RunSelfTest();
42	        Console.Error.WriteLine(
43	            "{\"error\":\"trust-origin usage: declare --ack BOOTSTRAP_TRUST_ORIGIN [--known-exceptions-file <path>] | --self-test\"}");
44	        return 2;
45	    }
46	
47	    // declare: 비대화형 거부(약한 안전장치), ack 확인, precondition 검사, record 생성.
48	    private static int RunDeclare(string[] args)
49	    {
50	        // 약한 안전장치(신원 증명 아님) — 비대화형 실행 기본 거부.
51	        // 프로그램은 사람과 AI를 구분 못 한다(HUMAN_DECLARED_NOT_CRYPTOGRAPHICALLY_VERIFIED).
52	        if (!NonInteractiveOverride && (Console.IsInputRedirected || !Environment.UserInteractive))
53	        {
54	            Console.Error.WriteLine(
55	                "{\"error\":\"비대화형 실행 기본 거부\",\"code\":\"non-interactive-rejected\","
56	                + "\"note\":\"HUMAN_DECLARED_NOT_CRYPTOGRAPHICALLY_VERIFIED — 프로그램은 사람과 AI를 구분하지 못합니다\"}");
57	            return 1;
58	        }
59	        var map = ParseFlagMap(args, 2);
60	        if (!map.TryGetValue("ack", out var ackVal) ||
61	            !string.Equals(ackVal, "BOOTSTRAP_TRUST_ORIGIN", StringComparison.OrdinalIgnoreCase))
62	        {
63	            Console.Error.WriteLine("{\"error\":\"--ack BOOTSTRAP_TRUST_ORIGIN 필요\",\"code\":\"ack-missing\"}");
64	            return 1;
65	        }
66	        string root;
67	        try { root = GitTools.FindRepoRoot(); }
68	        catch (Exception ex) { WriteError($"repo root 탐색 실패: {ex.Message}"); return 2; }
69	
70	        List<KnownException> knownExceptions = [];
71	        if (map.TryGetValue("known-exceptions-file", out var efile))
72	        {
73	            try { knownExceptions = ParseKnownExceptions(JsonNode.Parse(File.ReadAllText(efile, new UTF8Encoding(false)))); }
74	            catch (Exception ex) { WriteError($"known-exceptions-file 읽기 실패: {ex.Message}"); return 2; }
75	        }
76	        return RunDeclareCore(root, knownExceptions);
77	    }
78	
79	    // declare 핵심 — root를 명시적으로 받아 자기 시험과 production 경로를 공유한다.
80	    private static int RunDeclareCore(string root, List<KnownException> knownExceptions)
81	    {
82	        var recordPath = Path.GetFullPath(
83	            Path.Combine(root, RecordRelPath.Replace('/', Path.DirectorySeparatorChar)));
84	        var wsPath = Path.Combine(root, "docs", "handoff", "WORKSTATE.json");
85	        var logPath = Path.Combine(root, "docs", "handoff", "WORKSTATE.applier-log.jsonl");
86	        var precon = TestPrecon;
87	
88	        // 기존 epoch 확인: trustEpoch >= 1 이면 거부.
89	        var epochExit = CheckEpochGuard(recordPath);
90	        if (epochExit.HasValue) return epochExit.Value;
91	
92	        // WORKSTATE 읽기.
93	        if (!File.Exists(wsPath)) { WriteError("WORKSTATE.json not found"); return 2; }
94	        string wsContent;
95	        try { wsContent = File.ReadAllText(wsPath, new UTF8Encoding(false)); }
96	        catch (Exception ex) { WriteError($"WORKSTATE.json 읽기 실패: {ex.Message}"); return 2; }
97	
98	        // 선행조건 2: reconciliation 실행 + 부분집합 검사.
99	        var (reconResult, reconExit) = RunReconciliationCheck(wsPath, logPath, knownExceptions);
100	        if (reconExit.HasValue) return reconExit.Value;
101	
102	        // 선행조건 1·3·4·9·10 검사.
103	        var preconExit = CheckAllPreconditions(root, precon);
104	        if (preconExit.HasValue) return preconExit.Value;
105	
106	        // 선행조건 5: WORKSTATE hash / 선행조건 6: applier-log hash.
107	        var workstateSha256 = ComputeSha256(wsContent);
108	        var logContent = File.Exists(logPath) ? File.ReadAllText(logPath, new UTF8Encoding(false)) : "";
109	        var applierLogSha256 = ComputeSha256(logContent);
110	
111	        // 선행조건 7: baseline commit hash.
112	        var (baselineCommit, commitExit) = GetBaselineCommit(root, precon);
113	        if (commitExit.HasValue) return commitExit.Value;
114	
115	        // record 생성 — declarationCommit 없음(자기참조 방지). 이 경로 외에는 쓰지 않는다.
116	        return BuildAndWriteRecord(
117	            recordPath, baselineCommit!, workstateSha256, applierLogSha256, reconResult!, knownExceptions);
118	    }
119	
120	    // 기존 epoch 확인 — trustEpoch >= 1 이면 exit 1, 없으면 null.
121	    private static int? CheckEpochGuard(string recordPath)
122	    {
123	        if (!File.Exists(recordPath)) return null;
124	        try
125	        {
126	            var existing = JsonNode.Parse(File.ReadAllText(recordPath))?.AsObject();
127	            if ((existing?["trustEpoch"]?.GetValue<int>() ?? 0) >= 1)
128	            {
129	                WriteError("trustEpoch >= 1 이미 존재 — 재선언 거부. 새 trust origin은 VERIFIED_HUMAN_APPROVAL receipt 필요");
130	                return 1;
131	            }
132	        }
133	        catch { /* 파싱 불가 시 아래 CreateNew에서 처리 */ }
134	        return null;
135	    }
136	
137	    // reconciliation을 실행하고 failure ⊆ knownExceptions 부분집합 검사를 수행한다.
138	    private static (ReconciliationResult? result, int? exitCode) RunReconciliationCheck(
139	        string wsPath, string logPath, List<KnownException> knownExceptions)
140	    {
141	        ReconciliationResult reconResult;
142	        try { reconResult = HandoffIntegrityChecker.Run(new ReconciliationOptions(wsPath, logPath)); }
143	        catch (Exception ex) { WriteError($"reconciliation 실행 실패: {ex.Message}"); return (null, 2); }
144	
145	        // 하네스 오류 시 별도 중단 — subject가 없어 부분집합 검사를 우회할 수 있다.
146	        if (reconResult.HarnessErrors.Count > 0)
147	        {
148	            var errs = string.Join("; ", reconResult.HarnessErrors.Select(e => e.Code));
149	            WriteError($"reconciliation 하네스 오류 — 선행조건 2 검증 불가: {errs}");
150	            return (null, 2);
151	        }
152	
153	        // 정확한 집합 검사: failures == knownExceptions. 미명시 failure 또는 extra known exception → 선언 거부.
154	        var failureSubjects = reconResult.Failures
155	            .Select(f => f.Subject).Where(s => !string.IsNullOrWhiteSpace(s))
156	            .ToHashSet(StringComparer.OrdinalIgnoreCase);
157	        var knownSubjects = knownExceptions.Select(e => e.Subject).ToHashSet(StringComparer.OrdinalIgnoreCase);
158	        var unlisted = failureSubjects.Except(knownSubjects).ToList();
159	        var extraKnown = knownSubjects.Except(failureSubjects).ToList();
160	        if (unlisted.Count > 0 || extraKnown.Count > 0)
161	        {
162	            Console.Error.WriteLine(new JsonObject
163	            {
164	                ["error"] = "knownExceptions가 실제 failure와 정확히 일치하지 않음 — 선언 거부",
165	                ["code"] = unlisted.Count > 0 ? "unlisted-reconciliation-failure" : "extra-known-exceptions",
166	                ["unlistedSubjects"] = new JsonArray(unlisted.Select(s => (JsonNode?)s).ToArray()),
167	                ["extraKnownSubjects"] = new JsonArray(extraKnown.Select(s => (JsonNode?)s).ToArray()),
168	            }.ToJsonString());
169	            return (null, 1);
170	        }
171	        return (reconResult, null);
172	    }
173	
174	    // 선행조건 1·3·4·9·10을 검사한다. production 경로(precon=null)에서는 실제 확인을 수행한다. 미충족 시 exit code 반환.
175	    private static int? CheckAllPreconditions(string root, PreconOverride? precon)
176	    {
177	        // 선행조건 1: production에서 실제 dotnet build 실행. 기본값 true 금지.
178	        var buildOk = precon?.BuildVerified ?? CheckBuildProduction(root);
179	        if (!buildOk)
180	            { WriteError("선행조건 1 미충족 — clean build exit 0 필요 (dotnet build server -c Release -nologo)"); return 1; }
181	        var filesTracked = precon?.FilesTracked ?? CheckFilesTracked(root);
182	        if (!filesTracked)
183	            { WriteError("선행조건 3 미충족 — StateApplierCli.cs 또는 HandoffIntegrityChecker.cs가 git-tracked 상태가 아님"); return 1; }
184	        var noDirectMod = precon?.NoDirectMod ?? CheckNoDirectMod(root);
185	        if (!noDirectMod)
186	            { WriteError("선행조건 4 미충족 — WORKSTATE.json 또는 applier-log.jsonl가 working tree에서 직접 수정됨"); return 1; }
187	        // 선행조건 9: production에서 .claude/settings*.json hooks 확인. 기본값 true 금지.
188	        var autoOff = precon?.AutoLauncherOff ?? CheckAutoLauncherOff(root);
189	        if (!autoOff)
190	            { WriteError("선행조건 9 미충족 — 자동 launcher hooks 발견 또는 확인 불가"); return 1; }
191	        // 선행조건 10: production에서 state-transition PHASE_CHANGE가 trusted-human-receipt-required로 거부되는지 확인. 기본값 true 금지.
192	        var highRiskClosed = precon?.HighRiskClosed ?? CheckHighRiskClosed(root);
193	        if (!highRiskClosed)
194	            { WriteError("선행조건 10 미충족 — high-risk transition(PHASE_CHANGE/RECOVERY/REPLAY)이 fail-closed 되지 않음 또는 확인 불가"); return 1; }
195	        return null;
196	    }
197	
198	    // 선행조건 1: dotnet build server -c Release -nologo 실행 후 exit 0 여부를 반환한다.
199	    private static bool CheckBuildProduction(string root)
200	    {
201	        try
202	        {
203	            using var p = new Process();
204	            p.StartInfo = new ProcessStartInfo("dotnet", "build server -c Release -nologo")
205	            {
206	                WorkingDirectory = root,
207	                RedirectStandardOutput = true,
208	                RedirectStandardError = true,
209	                UseShellExecute = false,
210	            };
211	            p.Start();
212	            p.StandardOutput.ReadToEnd();
213	            p.StandardError.ReadToEnd();
214	            p.WaitForExit(120_000);
215	            return p.ExitCode == 0;
216	        }
217	        catch { return false; }
218	    }
219	
220	    // 선행조건 9: .claude/settings*.json에서 hooks 항목 유무로 자동 launcher 비활성을 판단한다.
221	    private static bool CheckAutoLauncherOff(string root)
222	    {
223	        foreach (var path in GetClaudeSettingsPaths(root))
224	        {
225	            if (!File.Exists(path)) continue;
226	            try
227	            {
228	                var node = JsonNode.Parse(File.ReadAllText(path, new System.Text.UTF8Encoding(false)));
229	                if (node?["hooks"] is JsonObject hooks && hooks.Count > 0) return false;
230	            }
231	            catch { /* 파싱 불가 — 이 파일은 skip */ }
232	        }
233	        return true;
234	    }
235	
236	    // 선행조건 9 보조: 검사 대상 Claude settings 경로 목록.
237	    private static System.Collections.Generic.IEnumerable<string> GetClaudeSettingsPaths(string root)
238	    {
239	        yield return Path.Combine(root, ".claude", "settings.json");
240	        yield return Path.Combine(root, ".claude", "settings.local.json");
241	        var home = Environment.GetFolderPath(Environment.SpecialFolder.UserProfile);
242	        if (!string.IsNullOrEmpty(home))
243	        {
244	            yield return Path.Combine(home, ".claude", "settings.json");
245	            yield return Path.Combine(home, ".claude", "settings.local.json");
246	        }
247	    }
248	
249	    // 선행조건 10: PHASE_CHANGE 전이가 trusted-human-receipt-required로 거부되는지 in-process fixture로 확인한다.
250	    private static bool CheckHighRiskClosed(string root)
251	    {
252	        var tmpEnv = Path.Combine(Path.GetTempPath(), $"to-hr-check-{Guid.NewGuid():N}.json");
253	        try
254	        {
255	            File.WriteAllText(tmpEnv,
256	                "{\"schemaVersion\":1,\"transitionKind\":\"PHASE_CHANGE\",\"transitionId\":\"trust-origin-high-risk-check\"}",
257	                new System.Text.UTF8Encoding(false));
258	            var origErr = Console.Error;
259	            Console.SetError(System.IO.TextWriter.Null);
260	            int exit;
261	            try { exit = StateApplierCli.Run(["state-transition", "apply", "--envelope", tmpEnv]); }
262	            finally { Console.SetError(origErr); }
263	            return exit == 1; // trusted-human-receipt-required → exit 1
264	        }
265	        catch { return false; }
266	        finally
267	        {
268	            try { if (File.Exists(tmpEnv)) File.Delete(tmpEnv); } catch { }
269	        }
270	    }
271	
272	    // 선행조건 7: baseline commit hash를 반환한다. 시험은 TestPrecon, production은 git.
273	    private static (string? commit, int? exitCode) GetBaselineCommit(string root, PreconOverride? precon)
274	    {
275	        if (precon is not null) return (precon.CommitHash, null);
276	        try { return (RunGitOutput(root, "rev-parse HEAD").Trim(), null); }
277	        catch (Exception ex) { WriteError($"git rev-parse HEAD 실패: {ex.Message}"); return (null, 2); }
278	    }
279	
280	    // record를 구성하고 고정 경로에 atomic-create로 쓴다.
281	    private static int BuildAndWriteRecord(
282	        string recordPath, string baselineCommit, string workstateSha256, string applierLogSha256,
283	        ReconciliationResult reconResult, List<KnownException> knownExceptions)
284	    {
285	        var reconVerdict = reconResult.Failures.Count == 0
286	            ? "VERIFIED_PASS" : "VERIFIED_PASS_WITH_KNOWN_EXCEPTIONS";
287	        // declarationCommit 필드 미포함 — 자기참조 방지. annotated tag로 연결.
288	        var record = new JsonObject
289	        {
290	            ["schemaVersion"] = 1, ["trustOriginId"] = "TO-2026-001", ["trustEpoch"] = 1,
291	            ["declarationType"] = "BOOTSTRAP_TRUST_ORIGIN", ["baselineCommit"] = baselineCommit,
292	            ["workstateSha256"] = workstateSha256, ["applierLogSha256"] = applierLogSha256,
293	            ["stateApplierSchemaVersion"] = 2, ["reconciliationSchemaVersion"] = 2,
294	            ["legacyHistory"] = "NOT_EXACTLY_REPLAY_VERIFIED",
295	            ["buildVerdict"] = "VERIFIED_PASS", ["reconciliationVerdict"] = reconVerdict,
296	            ["knownExceptions"] = BuildExceptionsArray(knownExceptions),
297	            ["normalTransitionReady"] = true, ["verifiedHumanApprovalReady"] = false,
298	            ["recoveryApplyReady"] = false, ["automatedExecutionReady"] = false,
299	            ["phaseChangeReady"] = false, ["replayReady"] = false,
300	            ["declaredBy"] = new JsonObject
301	            {
302	                ["actorType"] = "human", ["actorId"] = "bootstrap-operator",
303	                ["actorPath"] = "local-manual",
304	            },
305	            ["declarationStatus"] = "HUMAN_DECLARED_NOT_CRYPTOGRAPHICALLY_VERIFIED",
306	            ["declaredAt"] = DateTime.UtcNow.ToString("o"),
307	        };
308	        Directory.CreateDirectory(Path.GetDirectoryName(recordPath)!);
309	        try
310	        {
311	            using var fs = new FileStream(recordPath, FileMode.CreateNew, FileAccess.Write, FileShare.None);
312	            fs.Write(Encoding.UTF8.GetBytes(record.ToJsonString(WriteOptions)));
313	        }
314	        catch (IOException ex) { WriteError($"record atomic-create 실패 — 이미 존재하거나 쓰기 불가: {ex.Message}"); return 1; }
315	
316	        Console.WriteLine(new JsonObject
317	        {
318	            ["ok"] = true, ["trustOriginId"] = "TO-2026-001", ["trustEpoch"] = 1,
319	            ["baselineCommit"] = baselineCommit, ["workstateSha256"] = workstateSha256,
320	            ["applierLogSha256"] = applierLogSha256, ["recordPath"] = recordPath,
321	            ["reconciliationVerdict"] = reconVerdict,
322	            ["note"] = "선언 완료. 다음: git commit -m '[trust-origin] bootstrap TO-2026-001' → git tag trust-origin/TO-2026-001 <commitHash>",
323	        }.ToJsonString(WriteOptions));
324	        return 0;
325	    }
326	
327	    // --self-test: $TEMP 사본에서 5개 case를 in-process로 검증한다.
328	    private static int RunSelfTest()
329	    {
330	        var tmpBase = Path.Combine(Path.GetTempPath(), $"to-selftest-{Guid.NewGuid():N}");
331	        try { return RunSelfTestInDir(tmpBase); }
332	        finally
333	        {
334	            try { if (Directory.Exists(tmpBase)) Directory.Delete(tmpBase, recursive: true); } catch { }
335	            NonInteractiveOverride = false;
336	            TestPrecon = null;
337	        }
338	    }
339	
340	    // 임시 디렉토리에서 9개 case를 순서대로 실행하고 결과를 보고한다.
341	    private static int RunSelfTestInDir(string tmpRoot)
342	    {
343	        var wsDir = Path.Combine(tmpRoot, "docs", "handoff");
344	        var trustDir = Path.Combine(tmpRoot, "docs", "handoff", "trust-origin");
345	        Directory.CreateDirectory(wsDir);
346	        Directory.CreateDirectory(trustDir);
347	        Directory.CreateDirectory(Path.Combine(tmpRoot, ".git")); // FindRepoRoot 기준점
348	        var wsPath = Path.Combine(wsDir, "WORKSTATE.json");
349	        var logPath = Path.Combine(wsDir, "WORKSTATE.applier-log.jsonl");
350	        var recordPath = Path.Combine(trustDir, "TO-2026-001.json");
351	
352	        // knownExceptions에 명시된 오염 — LISTED-TRANSITION이 state에 있고 log에 없음 (declare-ok용)
353	        const string WsDirty = "{\"schemaVersion\":1,\"diId\":\"DI-00-04\",\"status\":\"in_progress\","
354	            + "\"blockers\":[],\"nextActions\":[\"test\"],\"phaseId\":\"P00\",\"wpId\":\"WP-00\","
355	            + "\"updatedAt\":\"2026-07-14\",\"updatedBy\":\"self-test\","
356	            + "\"appliedTransitions\":[{\"id\":\"LISTED-TRANSITION\",\"appliedAt\":\"2026-07-14T00:00:00Z\"}]}";
357	        // 깨끗한 WORKSTATE — appliedTransitions 없음 → reconciliation PASS
358	        const string WsClean = "{\"schemaVersion\":1,\"diId\":\"DI-00-04\",\"status\":\"in_progress\","
359	            + "\"blockers\":[],\"nextActions\":[\"test\"],\"phaseId\":\"P00\",\"wpId\":\"WP-00\","
360	            + "\"updatedAt\":\"2026-07-14\",\"updatedBy\":\"self-test\",\"appliedTransitions\":[]}";
361	        // 미명시 오염 — UNLISTED-TRANSITION이 state·log·knownExceptions 어디에도 없음 (unlisted-failure용)
362	        const string WsUnlisted = "{\"schemaVersion\":1,\"diId\":\"DI-00-04\",\"status\":\"in_progress\","
363	            + "\"blockers\":[],\"nextActions\":[\"test\"],\"phaseId\":\"P00\",\"wpId\":\"WP-00\","
364	            + "\"updatedAt\":\"2026-07-14\",\"updatedBy\":\"self-test\","
365	            + "\"appliedTransitions\":[{\"id\":\"UNLISTED-TRANSITION\",\"appliedAt\":\"2026-07-14T00:00:00Z\"}]}";
366	
367	        var goodPrecon = new PreconOverride(true, true, true, "abc123def456abc123def456abc123def456abc1", true, true);
368	        var mismatches = new JsonArray();
369	        var caseResults = new JsonArray();
370	        // 실행 순서: declare-ok → no-self-reference → extra-known-exception → unlisted-failure → redeclare → record-path-fixed → record-ready-flags-complete → build-verdict-not-forged → production-preconditions-not-default-true
371	        RunCaseDeclareOk(tmpRoot, wsPath, logPath, recordPath, WsDirty, goodPrecon, caseResults, mismatches);
372	        RunCaseNoSelfReference(recordPath, caseResults, mismatches);
373	        RunCaseExtraKnownException(tmpRoot, wsPath, logPath, recordPath, WsDirty, goodPrecon, caseResults, mismatches);
374	        RunCaseUnlistedFailure(tmpRoot, wsPath, logPath, recordPath, WsUnlisted, goodPrecon, caseResults, mismatches);
375	        RunCaseRedeclare(tmpRoot, wsPath, logPath, recordPath, WsClean, goodPrecon, caseResults, mismatches);
376	        RunCaseRecordPathFixed(tmpRoot, wsPath, logPath, recordPath, WsClean, goodPrecon, caseResults, mismatches);
377	        RunCaseRecordReadyFlagsComplete(recordPath, caseResults, mismatches);
378	        RunCaseBuildVerdictNotForged(tmpRoot, wsPath, logPath, recordPath, WsClean, goodPrecon, caseResults, mismatches);
379	        RunCaseProductionPreconNotDefaultTrue(tmpRoot, wsPath, logPath, recordPath, WsClean, caseResults, mismatches);
380	        NonInteractiveOverride = false; TestPrecon = null;
381	        if (mismatches.Count == 0)
382	        {
383	            Console.WriteLine(new JsonObject { ["selfTest"] = "trust-origin", ["verdict"] = "PASS",
384	                ["casesRun"] = caseResults.Count, ["cases"] = caseResults,
385	                ["selfFalsificationNote"] = "기대값을 틀리게 적으면 mismatches > 0 → exit 1. 판정선 4: 기대 epoch를 2로 바꿔 FAIL 실증.",
386	            }.ToJsonString(WriteOptions));
387	            return 0;
388	        }
389	        Console.Error.WriteLine(new JsonObject { ["selfTest"] = "trust-origin", ["verdict"] = "FAIL",
390	            ["mismatchCount"] = mismatches.Count, ["mismatches"] = mismatches, ["cases"] = caseResults,
391	        }.ToJsonString(WriteOptions));
392	        return 1;
393	    }
394	
395	    // case: declare-ok — failure가 knownExceptions에 명시돼 있으면 record 생성, trustEpoch=1.
396	    private static void RunCaseDeclareOk(
397	        string tmpRoot, string wsPath, string logPath, string recordPath,
398	        string wsDirty, PreconOverride precon, JsonArray caseResults, JsonArray mismatches)
399	    {
400	        ResetFixture(wsPath, wsDirty, logPath, recordPath);
401	        NonInteractiveOverride = true; TestPrecon = precon;
402	        var exceptions = new List<KnownException>
403	        {
404	            new("state-transition-not-logged", "LISTED-TRANSITION",
405	                "자기 시험용 fixture — state에 있지만 log에 없는 전이", "self-test fixture", "self-test only"),
406	        };
407	        var exit = RunDeclareCore(tmpRoot, exceptions);
408	        var recExists = File.Exists(recordPath);
409	        var epoch = 0; string? commit = null; var hasDC = false; string? verdict = null;
410	        if (recExists)
411	        {
412	            var rec = JsonNode.Parse(File.ReadAllText(recordPath))?.AsObject();
413	            epoch = rec?["trustEpoch"]?.GetValue<int>() ?? 0;
414	            commit = rec?["baselineCommit"]?.GetValue<string>();
415	            hasDC = rec?.ContainsKey("declarationCommit") ?? false;
416	            verdict = rec?["reconciliationVerdict"]?.GetValue<string>();
417	        }
418	        var ok = exit == 0 && recExists && epoch == 1 && commit == precon.CommitHash
419	            && !hasDC && verdict == "VERIFIED_PASS_WITH_KNOWN_EXCEPTIONS";
420	        caseResults.Add(new JsonObject { ["case"] = "declare-ok", ["exit"] = exit, ["recordExists"] = recExists,
421	            ["trustEpoch"] = epoch, ["commitMatch"] = (commit == precon.CommitHash),
422	            ["noDeclarationCommit"] = !hasDC, ["reconciliationVerdict"] = verdict, ["pass"] = ok });
423	        if (!ok) mismatches.Add(new JsonObject { ["case"] = "declare-ok",
424	            ["expected"] = "exit=0, record, epoch=1, commitMatch, no-DC, verdict=VERIFIED_PASS_WITH_KNOWN_EXCEPTIONS",
425	            ["actual"] = $"exit={exit},exists={recExists},epoch={epoch},commit={commit},hasDC={hasDC},verdict={verdict}" });
426	    }
427	
428	    // case: no-self-reference — declare-ok가 생성한 record에 declarationCommit 필드가 없다.
429	    private static void RunCaseNoSelfReference(string recordPath, JsonArray caseResults, JsonArray mismatches)
430	    {
431	        var recExists = File.Exists(recordPath);
432	        var hasDC = false;
433	        if (recExists)
434	        {
435	            try { var rec = JsonNode.Parse(File.ReadAllText(recordPath))?.AsObject(); hasDC = rec?.ContainsKey("declarationCommit") ?? false; }
436	            catch { hasDC = true; }
437	        }
438	        var ok = recExists && !hasDC;
439	        caseResults.Add(new JsonObject { ["case"] = "no-self-reference", ["recordExists"] = recExists, ["hasDeclarationCommit"] = hasDC, ["pass"] = ok });
440	        if (!ok) mismatches.Add(new JsonObject { ["case"] = "no-self-reference",
441	            ["expected"] = "record exists, declarationCommit 없음", ["actual"] = $"recExists={recExists},hasDC={hasDC}" });
442	    }
443	
444	    // case: unlisted-failure — reconciliation failure가 knownExceptions에 없으면 선언 거부.
445	    private static void RunCaseUnlistedFailure(
446	        string tmpRoot, string wsPath, string logPath, string recordPath,
447	        string wsUnlisted, PreconOverride precon, JsonArray caseResults, JsonArray mismatches)
448	    {
449	        ResetFixture(wsPath, wsUnlisted, logPath, recordPath);
450	        NonInteractiveOverride = true; TestPrecon = precon;
451	        var exit = RunDeclareCore(tmpRoot, []); // knownExceptions 비어 있음 → UNLISTED-TRANSITION 미명시 → 거부
452	        var recCreated = File.Exists(recordPath);
453	        var ok = exit == 1 && !recCreated;
454	        caseResults.Add(new JsonObject { ["case"] = "unlisted-failure", ["exit"] = exit, ["recordCreated"] = recCreated, ["pass"] = ok });
455	        if (!ok) mismatches.Add(new JsonObject { ["case"] = "unlisted-failure",
456	            ["expected"] = "exit=1 (선언 거부), record 미생성", ["actual"] = $"exit={exit},recordCreated={recCreated}" });
457	    }
458	
459	    // case: redeclare — trustEpoch >= 1 이미 존재하면 거부.
460	    private static void RunCaseRedeclare(
461	        string tmpRoot, string wsPath, string logPath, string recordPath,
462	        string wsClean, PreconOverride precon, JsonArray caseResults, JsonArray mismatches)
463	    {
464	        ResetFixture(wsPath, wsClean, logPath, recordPath);
465	        Directory.CreateDirectory(Path.GetDirectoryName(recordPath)!);
466	        File.WriteAllText(recordPath, "{\"schemaVersion\":1,\"trustOriginId\":\"TO-2026-001\",\"trustEpoch\":1}", new UTF8Encoding(false));
467	        NonInteractiveOverride = true; TestPrecon = precon;
468	        var exit = RunDeclareCore(tmpRoot, []);
469	        var ok = exit == 1;
470	        caseResults.Add(new JsonObject { ["case"] = "redeclare", ["exit"] = exit, ["pass"] = ok });
471	        if (!ok) mismatches.Add(new JsonObject { ["case"] = "redeclare",
472	            ["expected"] = "exit=1 (재선언 거부)", ["actual"] = $"exit={exit}" });
473	    }
474	
475	    // case: record-path-fixed — 선언은 canonical record 경로 외 다른 파일을 쓰지 않는다.
476	    private static void RunCaseRecordPathFixed(
477	        string tmpRoot, string wsPath, string logPath, string recordPath,
478	        string wsClean, PreconOverride precon, JsonArray caseResults, JsonArray mismatches)
479	    {
480	        ResetFixture(wsPath, wsClean, logPath, recordPath);
481	        NonInteractiveOverride = true; TestPrecon = precon;
482	        var beforeFiles = Directory.GetFiles(tmpRoot, "*", SearchOption.AllDirectories)
483	            .Select(Path.GetFullPath).ToHashSet(StringComparer.OrdinalIgnoreCase);
484	        var exit = RunDeclareCore(tmpRoot, []);
485	        var afterFiles = Directory.GetFiles(tmpRoot, "*", SearchOption.AllDirectories)
486	            .Select(Path.GetFullPath).ToHashSet(StringComparer.OrdinalIgnoreCase);
487	        var newFiles = afterFiles.Except(beforeFiles).ToList();
488	        var canonicalPath = Path.GetFullPath(recordPath);
489	        var onlyCanonical = exit == 0 && newFiles.Count == 1 &&
490	            string.Equals(newFiles[0], canonicalPath, StringComparison.OrdinalIgnoreCase);
491	        caseResults.Add(new JsonObject { ["case"] = "record-path-fixed", ["exit"] = exit,
492	            ["newFileCount"] = newFiles.Count, ["onlyCanonicalPath"] = onlyCanonical, ["pass"] = onlyCanonical });
493	        if (!onlyCanonical) mismatches.Add(new JsonObject { ["case"] = "record-path-fixed",
494	            ["expected"] = "exit=0, 신규 파일 1개만 (canonical path)",
495	            ["actual"] = $"exit={exit},newFiles=[{string.Join(";", newFiles)}]" });
496	    }
497	
498	    // case: extra-known-exception — knownExceptions가 실제 failure보다 많으면 선언 거부.
499	    private static void RunCaseExtraKnownException(
500	        string tmpRoot, string wsPath, string logPath, string recordPath,
501	        string wsDirty, PreconOverride precon, JsonArray caseResults, JsonArray mismatches)
502	    {
503	        ResetFixture(wsPath, wsDirty, logPath, recordPath);
504	        NonInteractiveOverride = true; TestPrecon = precon;
505	        var exceptions = new List<KnownException>
506	        {
507	            new("state-transition-not-logged", "LISTED-TRANSITION", "fixture 알려진 오염", "fixture", "fixture"),
508	            new("extra-never-observed", "FAKE-NEVER-OBSERVED", "실제 failure 없는 가짜 예외 — extra", "fixture", "fixture"),
509	        };
510	        var exit = RunDeclareCore(tmpRoot, exceptions);
511	        var recCreated = File.Exists(recordPath);
512	        var ok = exit == 1 && !recCreated;
513	        caseResults.Add(new JsonObject { ["case"] = "extra-known-exception", ["exit"] = exit,
514	            ["recordCreated"] = recCreated, ["pass"] = ok });
515	        if (!ok) mismatches.Add(new JsonObject { ["case"] = "extra-known-exception",
516	            ["expected"] = "exit=1 (extra known exception 거부), record 미생성",
517	            ["actual"] = $"exit={exit},recordCreated={recCreated}" });
518	    }
519	
520	    // case: record-ready-flags-complete — record에 phaseChangeReady:false, replayReady:false 존재.
521	    private static void RunCaseRecordReadyFlagsComplete(string recordPath, JsonArray caseResults, JsonArray mismatches)
522	    {
523	        var recExists = File.Exists(recordPath);
524	        bool hasPCR = false, hasRR = false, pcrFalse = false, rrFalse = false;
525	        if (recExists)
526	        {
527	            try
528	            {
529	                var rec = JsonNode.Parse(File.ReadAllText(recordPath))?.AsObject();
530	                hasPCR = rec?.ContainsKey("phaseChangeReady") ?? false;
531	                hasRR = rec?.ContainsKey("replayReady") ?? false;
532	                pcrFalse = rec?["phaseChangeReady"]?.GetValue<bool>() == false;
533	                rrFalse = rec?["replayReady"]?.GetValue<bool>() == false;
534	            }
535	            catch { }
536	        }
537	        var ok = recExists && hasPCR && hasRR && pcrFalse && rrFalse;
538	        caseResults.Add(new JsonObject { ["case"] = "record-ready-flags-complete",
539	            ["recordExists"] = recExists, ["hasPhaseChangeReady"] = hasPCR, ["hasReplayReady"] = hasRR,
540	            ["phaseChangeFalse"] = pcrFalse, ["replayFalse"] = rrFalse, ["pass"] = ok });
541	        if (!ok) mismatches.Add(new JsonObject { ["case"] = "record-ready-flags-complete",
542	            ["expected"] = "record에 phaseChangeReady:false, replayReady:false 존재",
543	            ["actual"] = $"exists={recExists},hasPCR={hasPCR},hasRR={hasRR},pcrFalse={pcrFalse},rrFalse={rrFalse}" });
544	    }
545	
546	    // case: build-verdict-not-forged — BuildVerified=false이면 exit 1, record 미생성.
547	    private static void RunCaseBuildVerdictNotForged(
548	        string tmpRoot, string wsPath, string logPath, string recordPath,
549	        string wsClean, PreconOverride precon, JsonArray caseResults, JsonArray mismatches)
550	    {
551	        var badPrecon = precon with { BuildVerified = false };
552	        ResetFixture(wsPath, wsClean, logPath, recordPath);
553	        NonInteractiveOverride = true; TestPrecon = badPrecon;
554	        var exit = RunDeclareCore(tmpRoot, []);
555	        var recCreated = File.Exists(recordPath);
556	        var ok = exit == 1 && !recCreated;
557	        caseResults.Add(new JsonObject { ["case"] = "build-verdict-not-forged", ["exit"] = exit,
558	            ["recordCreated"] = recCreated, ["pass"] = ok,
559	            ["note"] = "BuildVerified=false → 선언 거부 → VERIFIED_PASS record 생성 불가" });
560	        if (!ok) mismatches.Add(new JsonObject { ["case"] = "build-verdict-not-forged",
561	            ["expected"] = "exit=1, record 미생성 (build 미확인 경로는 VERIFIED_PASS 기록 불가)",
562	            ["actual"] = $"exit={exit},recordCreated={recCreated}" });
563	    }
564	
565	    // case: production-preconditions-not-default-true — TestPrecon=null 시 production path가 기본 true로 통과하지 못함.
566	    private static void RunCaseProductionPreconNotDefaultTrue(
567	        string tmpRoot, string wsPath, string logPath, string recordPath,
568	        string wsClean, JsonArray caseResults, JsonArray mismatches)
569	    {
570	        ResetFixture(wsPath, wsClean, logPath, recordPath);
571	        NonInteractiveOverride = true; TestPrecon = null; // production 경로 강제
572	        var exit = RunDeclareCore(tmpRoot, []);
573	        var recCreated = File.Exists(recordPath);
574	        // tmpRoot에는 dotnet 프로젝트 없음 → CheckBuildProduction 실패 → exit != 0
575	        var ok = exit != 0 && !recCreated;
576	        caseResults.Add(new JsonObject { ["case"] = "production-preconditions-not-default-true",
577	            ["exit"] = exit, ["recordCreated"] = recCreated, ["pass"] = ok,
578	            ["note"] = "TestPrecon=null: production path에서 build check 실행 — tmpRoot에 dotnet 프로젝트 없어 실패" });
579	        if (!ok) mismatches.Add(new JsonObject { ["case"] = "production-preconditions-not-default-true",
580	            ["expected"] = "exit!=0 (production precondition 실패), record 미생성",
581	            ["actual"] = $"exit={exit},recordCreated={recCreated}" });
582	    }
583	
584	    // 자기 시험용 fixture 초기화 — WORKSTATE·log를 고정값으로, record를 삭제.
585	    private static void ResetFixture(string wsPath, string wsContent, string logPath, string recordPath)
586	    {
587	        File.WriteAllText(wsPath, wsContent, new UTF8Encoding(false));
588	        File.WriteAllText(logPath, "", new UTF8Encoding(false));
589	        if (File.Exists(recordPath)) File.Delete(recordPath);
590	    }
591	
592	    // knownExceptions JSON 배열을 파싱한다.
593	    private static List<KnownException> ParseKnownExceptions(JsonNode? node)
594	    {
595	        var list = new List<KnownException>();
596	        if (node is not JsonArray arr) return list;
597	        foreach (var item in arr.OfType<JsonObject>())
598	        {
599	            var subject = item["subject"]?.GetValue<string>() ?? "";
600	            if (string.IsNullOrWhiteSpace(subject)) continue;
601	            list.Add(new KnownException(
602	                Code: item["code"]?.GetValue<string>() ?? "", Subject: subject,
603	                What: item["what"]?.GetValue<string>() ?? "", Why: item["why"]?.GetValue<string>() ?? "",
604	                WhyNotReplayed: item["whyNotReplayed"]?.GetValue<string>() ?? ""));
605	        }
606	        return list;
607	    }
608	
609	    // knownExceptions 목록을 JsonArray로 변환한다.
610	    private static JsonArray BuildExceptionsArray(List<KnownException> exceptions)
611	    {
612	        var arr = new JsonArray();
613	        foreach (var e in exceptions)
614	            arr.Add(new JsonObject { ["code"] = e.Code, ["subject"] = e.Subject, ["what"] = e.What,
615	                ["why"] = e.Why, ["whyNotReplayed"] = e.WhyNotReplayed });
616	        return arr;
617	    }
618	
619	    // StateApplierCli·HandoffIntegrityChecker가 git-tracked 상태인지 확인한다.
620	    private static bool CheckFilesTracked(string root)
621	    {
622	        foreach (var rel in new[] { "server/StateApplierCli.cs", "server/Harness/HandoffIntegrityChecker.cs" })
623	            if (RunGitExitCode(root, $"ls-files --error-unmatch \"{rel}\"") != 0) return false;
624	        return true;
625	    }
626	
627	    // WORKSTATE·applier-log가 working tree에서 직접 수정되지 않았는지 확인한다.
628	    private static bool CheckNoDirectMod(string root)
629	    {
630	        var output = RunGitOutput(root,
631	            "status --porcelain -- docs/handoff/WORKSTATE.json docs/handoff/WORKSTATE.applier-log.jsonl");
632	        return string.IsNullOrWhiteSpace(output);
633	    }
634	
635	    // git 명령의 exit code를 반환한다.
636	    private static int RunGitExitCode(string root, string arguments)
637	    {
638	        using var p = new Process();
639	        p.StartInfo = new ProcessStartInfo("git", arguments)
640	        {
641	            WorkingDirectory = root, RedirectStandardOutput = true,
642	            RedirectStandardError = true, UseShellExecute = false,
643	        };
644	        p.Start(); p.StandardOutput.ReadToEnd(); p.StandardError.ReadToEnd(); p.WaitForExit();
645	        return p.ExitCode;
646	    }
647	
648	    // git 명령의 stdout을 반환한다.
649	    private static string RunGitOutput(string root, string arguments)
650	    {
651	        using var p = new Process();
652	        p.StartInfo = new ProcessStartInfo("git", arguments)
653	        {
654	            WorkingDirectory = root, RedirectStandardOutput = true,
655	            RedirectStandardError = true, UseShellExecute = false,
656	        };
657	        p.Start(); var output = p.StandardOutput.ReadToEnd(); p.WaitForExit();
658	        return output;
659	    }
660	
661	    // --key value 쌍을 파싱한다.
662	    private static Dictionary<string, string> ParseFlagMap(string[] args, int startIndex)
663	    {
664	        var map = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
665	        for (var i = startIndex; i < args.Length; i++)
666	            if (args[i].StartsWith("--", StringComparison.Ordinal) && i + 1 < args.Length)
667	            { map[args[i][2..]] = args[i + 1]; i++; }
668	        return map;
669	    }
670	
671	    // SHA-256을 소문자 hex로 계산한다.
672	    private static string ComputeSha256(string content)
673	        => Convert.ToHexString(SHA256.HashData(Encoding.UTF8.GetBytes(content))).ToLowerInvariant();
674	
675	    // stderr에 JSON 오류 메시지를 출력한다.
676	    private static void WriteError(string message)
677	        => Console.Error.WriteLine($"{{\"error\":\"{message}\"}}");
678	}
