231	    // apply 핵심 — root를 명시적으로 받아 자기 시험과 production 경로 공유.
232	    private static int ApplyEnvelopeCore(
233	        (string root, string workstatePath, string logPath, byte[] rawWorkstateBytes, JsonObject workstate, string rawWorkstateStr) ctx,
234	        EnvelopeData envelope, bool dryRun)
235	    {
236	        // unknown transitionKind는 fail-closed — NORMAL/PHASE_CHANGE/RECOVERY/REPLAY 외 거부.
237	        if (!ValidTransitionKinds.Contains(envelope.TransitionKind))
238	            return Fail(1, envelope.TransitionId, "unknown-transition-kind",
239	                $"transitionKind='{envelope.TransitionKind}'은 알 수 없는 종류입니다 (허용: NORMAL, PHASE_CHANGE, RECOVERY, REPLAY)");
240	
241	        // high-risk transitionKind — receipt ledger 부재로 항상 fail-closed.
242	        if (HighRiskKinds.Contains(envelope.TransitionKind))
243	            return Fail(1, envelope.TransitionId, "trusted-human-receipt-required",
244	                $"transitionKind={envelope.TransitionKind}는 receipt ledger 부재로 이번 WP에서 fail-closed");
245	
246	        var (root, workstatePath, logPath, rawWorkstateBytes, workstate, rawWorkstateStr) = ctx;
247	
248	        // Step 1: request sha256 + candidate file hash 검증.
249	        var (_, request, evidenceExit) = VerifyApplyEvidence(envelope);
250	        if (evidenceExit.HasValue) return evidenceExit.Value;
251	
252	        // Step 2: reconciliation — 실패하면 일반 전이를 거부한다.
253	        // ★ 순서 정정(§1): reconciliation이 existing-transition보다 먼저여야 가짜 id 공격을 막는다.
254	        ReconciliationResult reconResult;
255	        try { reconResult = HandoffIntegrityChecker.Run(new ReconciliationOptions(workstatePath, logPath)); }
256	        catch (Exception ex) { WriteError($"reconciliation 실행 실패: {ex.Message}"); return 2; }
257	
258	        if (reconResult.Failures.Count > 0 || reconResult.HarnessErrors.Count > 0)
259	        {
260	            var codes = string.Join("; ", reconResult.Failures.Concat(reconResult.HarnessErrors).Select(f => f.Code));
261	            return Fail(1, envelope.TransitionId, "state-corrupted-preapply", $"reconciliation failed: {codes}");
262	        }
263	
264	        // Step 3: existing-transition 판정 (idempotent / collision / legacy-unverifiable).
265	        // ★ 순서 정정(§1): existing-transition이 pre-state hash보다 먼저여야 재시도가 산다.
266	        var existingResult = CheckExistingTransition(workstate, reconResult, envelope);
267	        if (existingResult.HasValue) return existingResult.Value;
268	
269	        // Steps 4-6: candidate 재계산 + 검증 + dry-run.
270	        var (recompCandidate, recompBytes, validateExit) =
271	            RunApplyValidatePhase(envelope, workstate, rawWorkstateStr, request!, dryRun, root);
272	        if (validateExit.HasValue) return validateExit.Value;
273	
274	        // Steps 7-10: atomic write + post-apply 검사 + v2 log.
275	        return RunApplyCommitPhase(
276	            envelope, workstatePath, logPath,
277	            rawWorkstateBytes, workstate, recompCandidate!, recompBytes!);
278	    }
