329	    // Steps 4-6: candidate 재계산 + hash 검증 + pre-state hash + request 검증 + dry-run 처리.
330	    private static (JsonObject? candidate, byte[]? bytes, int? earlyExit) RunApplyValidatePhase(
331	        EnvelopeData envelope, JsonObject workstate, string rawWorkstateStr,
332	        JsonObject request, bool dryRun, string root)
333	    {
334	        JsonObject recomputedCandidate;
335	        byte[] recomputedBytes;
336	        try
337	        {
338	            // Step 4: 메모리에서 candidate 재계산 + hash 검증 (TOCTOU 방어).
339	            recomputedCandidate = BuildCandidate(workstate, request, envelope.TransitionId, envelope.EffectiveAt);
340	            recomputedBytes = Encoding.UTF8.GetBytes(recomputedCandidate.ToJsonString(WriteOptions));
341	            var recomputedHash = Convert.ToHexString(SHA256.HashData(recomputedBytes)).ToLowerInvariant();
342	            if (!string.Equals(recomputedHash, envelope.ExpectedPostStateSha256, StringComparison.OrdinalIgnoreCase))
343	                return (null, null, Fail(1, envelope.TransitionId, "candidate-recompute-mismatch",
344	                    "recomputed candidate hash differs — WORKSTATE or request changed since prepare"));
345	        }
346	        catch (Exception ex) { WriteError($"candidate 재계산 실패: {ex.Message}"); return (null, null, 2); }
347	
348	        // Step 5: pre-state hash 검증 (미적용 ID에 한해 실행).
349	        var currentHash = ComputeSha256(rawWorkstateStr);
350	        if (!string.Equals(currentHash, envelope.ExpectedPreStateSha256, StringComparison.OrdinalIgnoreCase))
351	            return (null, null, Fail(1, envelope.TransitionId, "pre-state-hash-mismatch",
352	                $"expected={Short(envelope.ExpectedPreStateSha256)} actual={Short(currentHash)}"));
353	
354	        // Step 6: request 검증.
355	        var validErr = ValidateRequestForApply(request, envelope, workstate, root);
356	        if (validErr is not null)
357	            return (null, null, Fail(1, envelope.TransitionId, "validation-failed", validErr));
358	
359	        if (dryRun)
360	        {
361	            Console.WriteLine(new JsonObject
362	            {
363	                ["ok"] = true, ["dryRun"] = true,
364	                ["transitionId"] = envelope.TransitionId,
365	                ["previousStatus"] = workstate["status"]?.ToString(),
366	                ["newStatus"] = recomputedCandidate["status"]?.ToString(),
367	            }.ToJsonString(WriteOptions));
368	            return (null, null, 0);
369	        }
370	
371	        return (recomputedCandidate, recomputedBytes, null);
372	    }
