374	    // Steps 7-10: preimage 저장 → atomic write → test seam → post-apply 검사 → v2 log append.
375	    private static int RunApplyCommitPhase(
376	        EnvelopeData envelope, string workstatePath, string logPath,
377	        byte[] rawWorkstateBytes, JsonObject workstate, JsonObject recomputedCandidate, byte[] recomputedBytes)
378	    {
379	        // Step 7: preimage 저장 — atomic replace 전에 반드시 저장해야 한다.
380	        var preimage = rawWorkstateBytes;
381	        var preimageHash = Convert.ToHexString(SHA256.HashData(preimage)).ToLowerInvariant();
382	
383	        // Step 8: atomic replace — 재계산 bytes만 사용(candidate 파일은 evidence, write source 아님).
384	        try { var t = workstatePath + ".stateapplier.tmp"; File.WriteAllBytes(t, recomputedBytes); File.Move(t, workstatePath, overwrite: true); }
385	        catch (Exception ex) { WriteError($"atomic write 실패: {ex.Message}"); return 2; }
386	
387	        // 결정적 test seam — in-process 훅만 허용. 환경변수는 읽지 않는다.
388	        var seamFail = FailAfterWriteHook?.Invoke();
389	        if (seamFail is not null)
390	            return Rollback(workstatePath, logPath, preimage, preimageHash, envelope, seamFail);
391	
392	        // Step 9: 적용후 검사 — 항상 projection 실행.
393	        var projExit = RunProjection();
394	        if (projExit != 0)
395	            return Rollback(workstatePath, logPath, preimage, preimageHash, envelope, "projection-failed");
396	
397	        // 내부 checker — PendingTransitionId로 pending 면제 경로를 실증한다.
398	        ReconciliationResult reconAfter;
399	        try { reconAfter = HandoffIntegrityChecker.Run(new ReconciliationOptions(workstatePath, logPath, envelope.TransitionId)); }
400	        catch (Exception ex)
401	        {
402	            return Rollback(workstatePath, logPath, preimage, preimageHash, envelope,
403	                $"post-apply checker 실행 실패: {ex.Message}");
404	        }
405	
406	        if (reconAfter.Failures.Count > 0 || reconAfter.HarnessErrors.Count > 0)
407	        {
408	            var codes = string.Join("; ", reconAfter.Failures.Concat(reconAfter.HarnessErrors).Select(f => f.Code));
409	            return Rollback(workstatePath, logPath, preimage, preimageHash, envelope,
410	                $"post-apply-integrity-failed: {codes}");
411	        }
412	
413	        // Step 10: v2 log append — 성공 경로에서만.
414	        string newSha;
415	        try { newSha = ComputeSha256(File.ReadAllText(workstatePath, new UTF8Encoding(false))); }
416	        catch (Exception ex) { WriteError($"적용 후 hash 계산 실패: {ex.Message}"); return 2; }
417	
418	        var logContractHash = ComputeContractHash(
419	            envelope.TransitionId, envelope.TransitionKind, envelope.RequestSha256,
420	            envelope.ExpectedPreStateSha256, newSha, envelope.EffectiveAt);
421	        try
422	        {
423	            AppendApplierLogV2(logPath, envelope.TransitionId, "ok", 0, envelope.TransitionKind,
424	                envelope.RequestSha256, envelope.ExpectedPreStateSha256, newSha, logContractHash, envelope.EffectiveAt);
425	        }
426	        catch (Exception logEx)
427	        {
428	            Console.Error.WriteLine(new JsonObject
429	            {
430	                ["fatal"] = "AUDIT_LOG_STATE_UNKNOWN", ["transitionId"] = envelope.TransitionId,
431	                ["detail"] = $"v2 log append threw: {logEx.Message} — 다음 전이 금지, log 수동 검증 필요",
432	            }.ToJsonString());
433	            return 2;
434	        }
435	
436	        Console.WriteLine(new JsonObject
437	        {
438	            ["ok"] = true, ["transitionId"] = envelope.TransitionId,
439	            ["previousStatus"] = workstate["status"]?.ToString(),
440	            ["newStatus"] = recomputedCandidate["status"]?.ToString(),
441	            ["workstateSha256"] = newSha,
442	            ["pendingExemptionUsed"] = reconAfter.Metrics?.PendingExemptionApplied,
443	        }.ToJsonString(WriteOptions));
444	        return 0;
445	    }
