984	    // case: normal-apply — 주입 없음, exit 0, v2 log 기록, WS 변경.
985	    private static void RunCaseNormalApply(string tmpRoot, string reqPath, string wsPath, string wsContent,
986	        string logPath, string outDir, JsonArray caseResults, JsonArray mismatches)
987	    {
