992	        var env = ReadEnvelope(Path.Combine(outDir, "ST-NORMAL.envelope.json"));
993	        int? applyExit = null;
994	        if (env is not null && prepExit == 0)
995	        {
996	            var ctx = LoadWorkstateContextFromRoot(tmpRoot);
997	            if (ctx is not null) applyExit = ApplyEnvelopeCore(ctx.Value, env, false);
998	        }
999	        var logLines = File.Exists(logPath) ? File.ReadAllLines(logPath) : [];
1000	        var okLogged = logLines.Any(l => l.Contains("\"ok\"") && l.Contains("ST-NORMAL"));
1001	        var wsMoved = !string.Equals(ComputeSha256(File.ReadAllText(wsPath, new UTF8Encoding(false))), preimageHash);
1002	        var ok = applyExit == 0 && okLogged && wsMoved;
1003	        caseResults.Add(new JsonObject { ["case"] = "normal-apply", ["exit"] = applyExit, ["v2LogWritten"] = okLogged, ["wsChanged"] = wsMoved, ["pass"] = ok });
1004	        if (!ok) mismatches.Add(new JsonObject { ["case"] = "normal-apply", ["expected"] = "exit=0, v2-log-ok, ws-changed", ["actual"] = $"exit={applyExit},log={okLogged},ws={wsMoved}" });
