1038	        caseResults.Add(new JsonObject { ["case"] = "rollback-restores-log", ["noV2OkEntry"] = noV2OkEntry, ["pass"] = noV2OkEntry });
1039	        if (!noV2OkEntry) mismatches.Add(new JsonObject { ["case"] = "rollback-restores-log", ["expected"] = "v2-ok-log-not-written", ["actual"] = "v2-ok-log-was-written" });
1040	    }
